// The drug/supplement-interaction dataset, loaded onto the curated-dataset framework
// (issue #860 Track B, wave 2). Copies the mets.ts / icd10-common.ts shape: import the
// envelope JSON (generated by scripts/gen-drug-interactions.ts), validate it once with
// loadDataset(), and expose the rule ENTRIES + the concept vocabulary (in `meta`) the
// detector consumes. Identity is the unordered concept PAIR (pairStrategy) — the
// framework's sorted-pair machinery — so a rule resolves by its pair regardless of
// order and no two rules collide on a pair. The registry lists this for the linter;
// lib/drug-interactions.ts is the DOMAIN detector. Pure — no DB, no network.

import rawInteractions from "./data/drug-interactions.json";
import { loadDataset } from "./loader";
import { pairStrategy } from "./matcher";
import type {
  InteractionEntry,
  InteractionsMeta,
  RawConcept,
} from "@/scripts/gen-drug-interactions";

export type {
  InteractionEntry,
  InteractionsMeta,
  RawConcept,
  Severity,
} from "@/scripts/gen-drug-interactions";

// The validated dataset (envelope + guarantees). Throws at module load if the
// committed JSON ever violates the contract — a loud, early failure.
export const drugInteractionsDataset = loadDataset<
  InteractionEntry,
  InteractionsMeta
>(rawInteractions);

// Identity strategy: the unordered concept `pair` (sorted-pair key). For the linter.
export const drugInteractionPairStrategy = pairStrategy("pair");

// The concept vocabulary (dataset meta) and the interaction rules (entries) the
// detector consumes.
export const DRUG_CONCEPTS: RawConcept[] = (
  drugInteractionsDataset.meta as InteractionsMeta
).concepts;
export const DRUG_INTERACTIONS: InteractionEntry[] =
  drugInteractionsDataset.entries;
